/// Enum representing the role of a team member.
export enum MemberRole {
    Member = 'Member',
    Lead = 'Lead'
}

/// Enum representing backlog item categories.
export enum BacklogCategory {
    ClientFocused = 'ClientFocused',
    TechDebt = 'TechDebt',
    RAndD = 'RAndD'
}

/// Enum representing weekly plan states.
export enum WeekState {
    Setup = 'Setup',
    PlanningOpen = 'PlanningOpen',
    Frozen = 'Frozen',
    Completed = 'Completed'
}

/// Enum representing assignment status.
export enum AssignmentStatus {
    NotStarted = 'NotStarted',
    InProgress = 'InProgress',
    Done = 'Done',
    Blocked = 'Blocked'
}

import { inject } from '@angular/core';
import { Router, type CanActivateFn } from '@angular/router';
import { AuthService } from '../services/auth.service';
import { TeamMemberService } from '../services/team-member.service';

/** Redirects to /setup if no team members exist. */
export const hasTeamGuard: CanActivateFn = () => {
    const teamService = inject(TeamMemberService);
    const router = inject(Router);

    if (!teamService.anyExist()) {
        router.navigate(['/setup']);
        return false;
    }
    return true;
};

/** Redirects to /login if user is not logged in. */
export const authGuard: CanActivateFn = () => {
    const authService = inject(AuthService);
    const router = inject(Router);

    if (!authService.isLoggedIn()) {
        router.navigate(['/login']);
        return false;
    }
    return true;
};

import { MemberRole } from '../enums/enums';

/// Represents a team member from the API.
export interface TeamMember {
    id: string;
    name: string;
    role: MemberRole;
    isActive: boolean;
    createdAt: string;
}

import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { TeamMember } from '../models/team-member.model';
import { MemberRole } from '../enums/enums';

/**
 * Tracks the currently logged-in user in memory only.
 * Page refresh = must re-select user on "Who are you?" screen.
 * No browser storage used — all team data lives in Azure SQL via the API.
 */
@Injectable({
    providedIn: 'root'
})
export class AuthService {
    private currentUserSubject = new BehaviorSubject<TeamMember | null>(null);

    /** Observable of the current logged-in user. */
    currentUser$ = this.currentUserSubject.asObservable();

    /** Log in as a team member (in-memory only). */
    login(member: TeamMember): void {
        this.currentUserSubject.next(member);
    }

    /** Log out the current user. */
    logout(): void {
        this.currentUserSubject.next(null);
    }

    /** Get the current user synchronously. */
    getCurrentUser(): TeamMember | null {
        return this.currentUserSubject.getValue();
    }

    /** Check if a user is logged in. */
    isLoggedIn(): boolean {
        return this.getCurrentUser() !== null;
    }

    /** Check if the current user is the Team Lead. */
    isLead(): boolean {
        return this.getCurrentUser()?.role === MemberRole.Lead;
    }

    /** Update the stored user (e.g., when role changes). */
    refreshUser(updatedMember: TeamMember): void {
        this.currentUserSubject.next(updatedMember);
    }
}

import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { BehaviorSubject, Observable, tap } from 'rxjs';
import { BacklogCategory } from '../enums/enums';
import { environment } from '../../../environments/environment';

/// <summary>Backlog item model matching the API response.</summary>
export interface BacklogItem {
    id: string;
    title: string;
    description: string | null;
    category: BacklogCategory;
    estimatedHours: number;
    isArchived: boolean;
    createdAt: string;
}

/**
 * Service managing backlog items via the .NET REST API.
 * Uses BehaviorSubject for reactive updates after each API call.
 */
@Injectable({
    providedIn: 'root'
})
export class BacklogService {
    private readonly apiUrl = `${environment.apiUrl}/backlog-items`;
    private itemsSubject = new BehaviorSubject<BacklogItem[]>([]);

    /** Observable stream of all backlog items (non-archived by default). */
    items$ = this.itemsSubject.asObservable();

    constructor(private http: HttpClient) {
        this.refresh();
    }

    /** Refresh items from the API (includes archived for full list). */
    refresh(includeArchived = true): void {
        let params = new HttpParams();
        if (includeArchived) params = params.set('includeArchived', 'true');

        this.http.get<BacklogItem[]>(this.apiUrl, { params }).subscribe({
            next: items => this.itemsSubject.next(items),
            error: () => { }
        });
    }

    /** Get all items from cache. */
    getItems(): BacklogItem[] {
        return this.itemsSubject.getValue();
    }

    /** Get non-archived items from cache. */
    getActiveItems(): BacklogItem[] {
        return this.getItems().filter(i => !i.isArchived);
    }

    /** Create a new backlog item. */
    create(item: { title: string; description?: string; category: BacklogCategory; estimatedHours: number }): Observable<BacklogItem> {
        return this.http.post<BacklogItem>(this.apiUrl, item).pipe(
            tap(() => this.refresh())
        );
    }

    /** Update a backlog item. */
    update(id: string, item: { title: string; description?: string; category: BacklogCategory; estimatedHours: number }): Observable<BacklogItem> {
        return this.http.put<BacklogItem>(`${this.apiUrl}/${id}`, item).pipe(
            tap(() => this.refresh())
        );
    }

    /** Archive a backlog item. */
    archive(id: string): Observable<void> {
        return this.http.put<void>(`${this.apiUrl}/${id}/archive`, {}).pipe(
            tap(() => this.refresh())
        );
    }

    /** Unarchive a backlog item. */
    unarchive(id: string): Observable<void> {
        return this.http.put<void>(`${this.apiUrl}/${id}/unarchive`, {}).pipe(
            tap(() => this.refresh())
        );
    }

    /** Delete a backlog item permanently. */
    delete(id: string): Observable<void> {
        return this.http.delete<void>(`${this.apiUrl}/${id}`).pipe(
            tap(() => this.refresh())
        );
    }
}

import { Injectable } from '@angular/core';
import { BehaviorSubject, Observable } from 'rxjs';

/**
 * All screens in the app. No URL routing — just state-driven screen switching.
 */
export type Screen =
    | 'loading'
    | 'setup'
    | 'login'
    | 'home'
    | 'manage-team'
    | 'manage-backlog'
    | 'start-week'
    | 'setup-week'
    | 'plan-my-work'
    | 'review-freeze'
    | 'update-progress'
    | 'team-progress'
    | 'past-weeks';

@Injectable({
    providedIn: 'root'
})
export class NavigationService {
    private screenSubject = new BehaviorSubject<Screen>('loading');
    private historyStack: Screen[] = [];

    /** Observable of the current screen. */
    currentScreen$: Observable<Screen> = this.screenSubject.asObservable();

    /** Navigate to a screen. */
    navigateTo(screen: Screen): void {
        const current = this.screenSubject.getValue();
        if (current !== screen) {
            this.historyStack.push(current);
        }
        this.screenSubject.next(screen);
    }

    /** Go back to the previous screen. */
    goBack(): void {
        if (this.historyStack.length > 0) {
            const prev = this.historyStack.pop()!;
            this.screenSubject.next(prev);
        }
    }

    /** Get the current screen synchronously. */
    getCurrentScreen(): Screen {
        return this.screenSubject.getValue();
    }
}

import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { BehaviorSubject, Observable, tap, firstValueFrom } from 'rxjs';
import { TeamMember } from '../models/team-member.model';
import { MemberRole } from '../enums/enums';
import { environment } from '../../../environments/environment';

/**
 * Service managing team members via the .NET REST API.
 * Uses BehaviorSubject for reactive updates after each API call.
 */
@Injectable({
    providedIn: 'root'
})
export class TeamMemberService {
    private readonly apiUrl = `${environment.apiUrl}/team-members`;
    private membersSubject = new BehaviorSubject<TeamMember[]>([]);

    /** Observable stream of current team members. */
    members$ = this.membersSubject.asObservable();

    constructor(private http: HttpClient) {
        this.refresh();
    }

    /** Refresh the local cache from the API. */
    refresh(): void {
        this.http.get<TeamMember[]>(this.apiUrl).subscribe({
            next: members => this.membersSubject.next(members),
            error: () => { } // Silent fail on initial load (API might not be ready)
        });
    }

    /** Get current members array (synchronous from cache). */
    getMembers(): TeamMember[] {
        return this.membersSubject.getValue();
    }

    /** Check if any team members exist. */
    anyExist(): boolean {
        return this.getMembers().length > 0;
    }

    /** Add a new team member via API. First person becomes Lead automatically. */
    create(name: string): Observable<TeamMember> {
        return this.http.post<TeamMember>(this.apiUrl, { name }).pipe(
            tap(() => this.refresh())
        );
    }

    /** Update a team member's name. */
    update(id: string, name: string): Observable<TeamMember> {
        return this.http.put<TeamMember>(`${this.apiUrl}/${id}`, { name }).pipe(
            tap(() => this.refresh())
        );
    }

    /** Make a member the Team Lead. */
    makeLead(id: string): Observable<TeamMember> {
        return this.http.put<TeamMember>(`${this.apiUrl}/${id}/make-lead`, {}).pipe(
            tap(() => this.refresh())
        );
    }

    /** Remove (deactivate) a team member. */
    remove(id: string): Observable<void> {
        return this.http.delete<void>(`${this.apiUrl}/${id}`).pipe(
            tap(() => this.refresh())
        );
    }

    /** Check if any members exist (API call). */
    checkExists(): Observable<boolean> {
        return this.http.get<boolean>(`${this.apiUrl}/exists`);
    }

    /** Get all active team members from the API. */
    getAll(): Observable<TeamMember[]> {
        return this.http.get<TeamMember[]>(this.apiUrl);
    }

    /** Bulk-save team members (for setup flow). Returns Promise that resolves when all are created. */
    async bulkCreate(members: { name: string; role: MemberRole }[]): Promise<void> {
        for (const member of members) {
            const created = await firstValueFrom(
                this.http.post<TeamMember>(this.apiUrl, { name: member.name })
            );
            // If this member should be lead and isn't, make them lead
            if (member.role === MemberRole.Lead && created.role !== MemberRole.Lead) {
                await firstValueFrom(
                    this.http.put<TeamMember>(`${this.apiUrl}/${created.id}/make-lead`, {})
                );
            }
        }
        this.refresh();
    }
}

import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';

export interface Toast {
    id: number;
    message: string;
    type: 'success' | 'warning' | 'error';
}

@Injectable({
    providedIn: 'root'
})
export class ToastService {
    private toasts: Toast[] = [];
    private toastsSubject = new BehaviorSubject<Toast[]>([]);
    private nextId = 0;

    toasts$ = this.toastsSubject.asObservable();

    /** Show a success toast that auto-dismisses after 4 seconds. */
    success(message: string): void {
        this.show(message, 'success');
    }

    /** Show a warning toast that auto-dismisses after 4 seconds. */
    warning(message: string): void {
        this.show(message, 'warning');
    }

    /** Show an error toast that auto-dismisses after 5 seconds. */
    error(message: string): void {
        this.show(message, 'error');
    }

    /** Remove a toast by its ID. */
    dismiss(id: number): void {
        this.toasts = this.toasts.filter(t => t.id !== id);
        this.toastsSubject.next([...this.toasts]);
    }

    private show(message: string, type: Toast['type']): void {
        const id = this.nextId++;
        const toast: Toast = { id, message, type };
        this.toasts.push(toast);
        this.toastsSubject.next([...this.toasts]);

        const duration = type === 'error' ? 5000 : 4000;
        setTimeout(() => this.dismiss(id), duration);
    }
}

